targets.expr:
(
  # 1. K3S 클러스터 노드들 (master, worker1, worker2, db1)
  100 - (
    avg by (instance) (
      rate(node_cpu_seconds_total{mode="idle", job="kubernetes-nodes-exporter"}[5m])
    ) * 100
  )
)
OR
(
  # 2. 모니터링 서버 (업데이트된 필터)
  100 - (
    avg by (instance) (
      label_replace(
        # 사용자님의 'up' 메트릭에 찍힌 job="node-exporter"를 직접 타겟팅합니다.
        rate(node_cpu_seconds_total{mode="idle", job="node-exporter"}[5m]),
        "instance", "monitoring", "instance", ".*"
      )
    ) * 100
  )
)

(
  # 1. K3S 클러스터 노드들 (master, worker1, worker2, db1)
  # 이미 instance 라벨이 서버 이름으로 정리되어 있어 조인이 필요 없습니다.
  100 * (
    1 - (
      avg by (instance) (
        node_memory_MemAvailable_bytes{job="kubernetes-nodes-exporter"} 
        / 
        node_memory_MemTotal_bytes{job="kubernetes-nodes-exporter"}
      )
    )
  )
)
OR
(
  # 2. 모니터링 서버 (monitoring-server로 이름 변경)
  # up 메트릭에서 확인된 job="node-exporter"를 사용합니다.
  100 * (
    1 - (
      avg by (instance) (
        label_replace(
          (node_memory_MemAvailable_bytes{job="node-exporter"} / node_memory_MemTotal_bytes{job="node-exporter"}),
          "instance", "monitoring", "instance", ".*"
        )
      )
    )
  )
)

(
  # 1. K3S 클러스터 노드들 (master, worker1, worker2, db1)
  # 루트(/) 마운트포인트의 사용 가능한 공간 비율을 계산하여 사용량(%)으로 변환합니다.
  100 - (
    avg by (instance) (
      node_filesystem_avail_bytes{mountpoint="/", job="kubernetes-nodes-exporter"} 
      / 
      node_filesystem_size_bytes{mountpoint="/", job="kubernetes-nodes-exporter"}
    ) * 100
  )
)
OR
(
  # 2. 모니터링 서버 (monitoring-server)
  # 'up' 메트릭에서 확인된 job="node-exporter" 데이터를 사용합니다.
  100 - (
    avg by (instance) (
      label_replace(
        (node_filesystem_avail_bytes{mountpoint="/", job="node-exporter"} 
        / 
        node_filesystem_size_bytes{mountpoint="/", job="node-exporter"}),
        "instance", "monitoring", "instance", ".*"
      )
    ) * 100
  )
)

# [사용량 / 제한치 * 100]
sum(
  rate(container_cpu_usage_seconds_total{namespace="default", pod=~"nginx-web.*", container="nginx"}[5m])
) by (pod)
/
sum(
  kube_pod_container_resource_limits{resource="cpu", namespace="default", pod=~"nginx-web.*", container="nginx"}
) by (pod)
* 100
